def process(center, distance):
    # Simple random sampler - runtime provides better nav-aware sampling when available
    import random, math
    if center is None:
        center = (0.0, 0.0, 0.0)
    d = distance if distance and distance > 0 else 1.0
    # Uniform in sphere via rejection sampling
    while True:
        x = random.uniform(-1.0, 1.0)
        y = random.uniform(-1.0, 1.0)
        z = random.uniform(-1.0, 1.0)
        if x*x + y*y + z*z <= 1.0:
            return (center[0] + x * d, center[1] + y * d, center[2] + z * d)
